import type { ModelContextItem, ModelProvider, ModelRequest, ModelResponse, Tool } from '../harness/types.js'
import Anthropic from '@anthropic-ai/sdk'
import OpenAI from 'openai'
import type { ModelConfig } from './service.js'

function shouldDebugProviderPayloads() {
  return process.env.MYAGENT_DEBUG_PROVIDER === '1'
}

function debugProviderPayload(label: string, payload: unknown) {
  if (!shouldDebugProviderPayloads()) return
  console.error(`[myagent][provider:${label}] ${JSON.stringify(payload, null, 2)}`)
}

export function buildAnthropicMessages(request: ModelRequest) {
  const contextItems = request.contextItems ?? request.messages.map((message) => ({ kind: 'message', message }) satisfies ModelContextItem)
  const messages: Array<Record<string, unknown>> = []
  let pendingToolResults: Array<Record<string, unknown>> = []

  for (const item of contextItems) {
    if (item.kind === 'message') {
      if (pendingToolResults.length > 0) {
        messages.push({ role: 'user', content: pendingToolResults })
        pendingToolResults = []
      }
      if (item.message.role !== 'user' && item.message.role !== 'assistant') continue
      messages.push({
        role: item.message.role,
        content: item.message.content,
      })
      continue
    }

    if (item.kind === 'tool_use') {
      const lastMessage = messages[messages.length - 1]
      const toolUseBlock = {
        type: 'tool_use',
        id: item.id,
        name: item.tool,
        input: item.input,
      }
      if (lastMessage && lastMessage.role === 'assistant') {
        const existingContent = lastMessage.content as unknown[]
        lastMessage.content = Array.isArray(existingContent)
          ? [...existingContent, toolUseBlock]
          : [existingContent, toolUseBlock]
      } else {
        messages.push({
          role: 'assistant',
          content: [toolUseBlock],
        })
      }
      continue
    }

    pendingToolResults.push({
      type: 'tool_result',
      tool_use_id: item.toolUseId,
      content: item.content,
      is_error: !item.ok,
    })
  }

  if (pendingToolResults.length > 0) {
    messages.push({ role: 'user', content: pendingToolResults })
  }

  return messages
}

export function buildOpenAIMessages(request: ModelRequest): OpenAI.Chat.ChatCompletionMessageParam[] {
  const contextItems = request.contextItems ?? request.messages.map((message) => ({ kind: 'message', message }) satisfies ModelContextItem)
  const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
    ...(request.system ? [{ role: 'system' as const, content: request.system }] : []),
  ]

  for (const item of contextItems) {
    if (item.kind === 'message') {
      if (item.message.role !== 'user' && item.message.role !== 'assistant') continue
      messages.push({
        role: item.message.role,
        content: item.message.content,
      })
      continue
    }

    if (item.kind === 'tool_use') {
      const lastMessage = messages[messages.length - 1]
      const toolCall = {
        id: item.id,
        type: 'function' as const,
        function: {
          name: item.tool,
          arguments: JSON.stringify(item.input ?? {}),
        },
      }
      if (lastMessage && lastMessage.role === 'assistant') {
        const existing = (lastMessage as { tool_calls?: unknown[] }).tool_calls ?? []
        ;(lastMessage as { tool_calls: unknown[] }).tool_calls = [...existing, toolCall]
      } else {
        messages.push({
          role: 'assistant',
          content: '',
          tool_calls: [toolCall],
        })
      }
      continue
    }

    messages.push({
      role: 'tool',
      content: item.content,
      tool_call_id: item.toolUseId,
    })
  }

  return messages
}

export function buildAnthropicTools(tools: Tool[] = []) {
  return tools.map((tool) => ({
    name: tool.name,
    description: tool.description,
    input_schema: tool.inputSchema,
  }))
}

export function buildOpenAITools(tools: Tool[] = []) {
  return tools.map((tool) => ({
    type: 'function' as const,
    function: {
      name: tool.name,
      description: tool.description,
      parameters: tool.inputSchema as Record<string, unknown>,
    },
  }))
}

export function buildAnthropicPayload(request: ModelRequest) {
  const tools = buildAnthropicTools(request.tools)
  return {
    model: request.model,
    max_tokens: request.maxTokens ?? 4096,
    messages: buildAnthropicMessages(request) as unknown as Anthropic.Messages.MessageParam[],
    ...(request.system ? { system: request.system } : {}),
    ...(tools.length > 0
      ? {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          tools: tools as any,
          tool_choice: { type: 'auto', disable_parallel_tool_use: true } as const,
        }
      : {}),
  }
}

export function buildOpenAIPayload(request: ModelRequest) {
  const tools = buildOpenAITools(request.tools)
  return {
    model: request.model,
    messages: buildOpenAIMessages(request),
    ...(tools.length > 0
      ? {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          tools: tools as any,
        }
      : {}),
  }
}

export class AnthropicProvider implements ModelProvider {
  name = 'anthropic'
  private client: Anthropic

  constructor(config: ModelConfig) {
    this.client = new Anthropic({
      apiKey: config.apiKey,
      baseURL: config.baseUrl,
    })
  }

  async createMessage(request: ModelRequest): Promise<ModelResponse> {
    const payload = buildAnthropicPayload(request)
    debugProviderPayload('anthropic', payload)
    const response = await this.client.messages.create(payload)

    const content = response.content.find((c) => c.type === 'text')
    const toolUses = response.content.filter((c) => c.type === 'tool_use')

    return {
      content: content?.type === 'text' ? content.text : '',
      toolCalls: toolUses.map((c) => {
        if (c.type !== 'tool_use') throw new Error('Unexpected content type')
        return {
          id: c.id,
          name: c.name,
          input: c.input,
        }
      }),
    }
  }
}

export class OpenAIProvider implements ModelProvider {
  name = 'openai'
  private client: OpenAI

  constructor(config: ModelConfig) {
    this.client = new OpenAI({
      apiKey: config.apiKey,
      baseURL: config.baseUrl,
    })
  }

  async createMessage(request: ModelRequest): Promise<ModelResponse> {
    const payload = buildOpenAIPayload(request)
    debugProviderPayload('openai', payload)
    const response = await this.client.chat.completions.create(payload)

    const choice = response.choices[0]
    const message = choice?.message

    const toolCalls =
      message?.tool_calls?.map((tc) => {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const fn = tc as any
        return {
          id: tc.id,
          name: fn.function.name,
          input: typeof fn.function.arguments === 'string'
            ? JSON.parse(fn.function.arguments)
            : fn.function.arguments,
        }
      }) ?? []

    return {
      content: message?.content ?? '',
      toolCalls,
    }
  }
}

export class ProviderRegistry {
  private providers: Map<string, ModelProvider> = new Map()

  register(provider: ModelProvider): void {
    this.providers.set(provider.name, provider)
  }

  get(name: string): ModelProvider | undefined {
    return this.providers.get(name)
  }

  has(name: string): boolean {
    return this.providers.has(name)
  }

  list(): string[] {
    return Array.from(this.providers.keys())
  }
}

export function createProvider(config: ModelConfig): ModelProvider | undefined {
  switch (config.provider) {
    case 'anthropic':
      return new AnthropicProvider(config)
    case 'openai':
      return new OpenAIProvider(config)
    default:
      return undefined
  }
}

import { readJsonFile, writeJsonFile } from '../utils/json.js'
import { getConfigPath } from '../utils/paths.js'

export interface ModelConfig {
  provider: string
  model: string
  apiKey?: string
  baseUrl?: string
}

export interface AgentConfig {
  system?: string
  maxTokens?: number
  contextBudget?: number
  sessionDir?: string
}

export interface Config {
  models: Record<string, ModelConfig>
  defaultModel?: string
  agent: AgentConfig
}

const DEFAULT_CONFIG: Config = {
  models: {
    anthropic: {
      provider: 'anthropic',
      model: 'claude-opus-4-7',
    },
  },
  defaultModel: 'anthropic',
  agent: {
    contextBudget: 100_000,
  },
}

export class ConfigService {
  private config: Config
  private configPath: string

  constructor(cwd: string) {
    this.configPath = getConfigPath(cwd)
    this.config = { ...DEFAULT_CONFIG }
  }

  async load(): Promise<void> {
    this.config = await readJsonFile(this.configPath, DEFAULT_CONFIG)
  }

  async save(): Promise<void> {
    await writeJsonFile(this.configPath, this.config)
  }

  get(): Config {
    return this.config
  }

  getModel(name: string): ModelConfig | undefined {
    return this.config.models[name]
  }

  getDefaultModel(): ModelConfig | undefined {
    if (!this.config.defaultModel) return undefined
    return this.config.models[this.config.defaultModel]
  }

  setDefaultModel(name: string): void {
    if (this.config.models[name]) {
      this.config.defaultModel = name
    }
  }

  addModel(name: string, model: ModelConfig): void {
    this.config.models[name] = model
  }
}

export type RiskLevel = 'safe' | 'confirm' | 'dangerous'

export type ChatRole = 'user' | 'assistant' | 'system' | 'tool'

export interface ChatMessage {
  id: string
  role: ChatRole
  content: string
  createdAt: string
  model?: string
}

export interface ToolUseRecord {
  id: string
  type: 'tool_use'
  tool: string
  input: unknown
  riskLevel: RiskLevel
  createdAt: string
}

export interface ToolResultRecord {
  id: string
  type: 'tool_result'
  toolUseId: string
  tool: string
  ok: boolean
  content: string
  createdAt: string
}

export interface ToolApprovalRecord {
  id: string
  type: 'tool_approval'
  tool: string
  input: unknown
  approved: boolean
  riskLevel: RiskLevel
  createdAt: string
}

export type SessionRecord =
  | ({ type: 'message' } & ChatMessage)
  | ToolUseRecord
  | ToolResultRecord
  | ToolApprovalRecord

export interface ToolContext {
  cwd: string
  sessionId: string
  readFiles: Set<string>
}

export interface ToolResult {
  ok: boolean
  content: string
  metadata?: Record<string, unknown>
}

export interface Tool {
  name: string
  description: string
  inputSchema: unknown
  riskLevel: RiskLevel
  execute(input: unknown, context: ToolContext): Promise<ToolResult>
}

export interface CommandContext {
  cwd: string
  writeLine(message: string): void
}

export interface Command {
  name: string
  description: string
  run(args: string[], context: CommandContext): Promise<void>
}

export interface ToolCall {
  id: string
  name: string
  input: unknown
}

export interface ContextChatMessage {
  kind: 'message'
  message: ChatMessage
}

export interface ContextToolUse {
  kind: 'tool_use'
  id: string
  tool: string
  input: unknown
}

export interface ContextToolResult {
  kind: 'tool_result'
  toolUseId: string
  tool: string
  ok: boolean
  content: string
}

export type ModelContextItem = ContextChatMessage | ContextToolUse | ContextToolResult

export interface ModelRequest {
  system?: string
  messages: ChatMessage[]
  contextItems?: ModelContextItem[]
  tools?: Tool[]
  model: string
  maxTokens?: number
}

export interface ModelResponse {
  content: string
  toolCalls: ToolCall[]
}

export interface ModelProvider {
  name: string
  createMessage(request: ModelRequest): Promise<ModelResponse>
}

import type { ChatMessage, ModelContextItem, SessionRecord, Tool } from './types.js'
import { PromptComposer } from '../prompts/composer.js'
import { ContextBudget } from '../prompts/budget.js'

export interface BuildContextInput {
  records: SessionRecord[]
  tools: Tool[]
  system?: string
  budget?: ContextBudget
}

export interface BuiltContext {
  system?: string
  messages: ChatMessage[]
  contextItems: ModelContextItem[]
}

export class ContextBuilder {
  constructor(
    private readonly composer = new PromptComposer(),
    private readonly defaultBudget = new ContextBudget(),
  ) {}

  build(input: BuildContextInput): BuiltContext {
    const messages = input.records
      .filter((record): record is SessionRecord & { type: 'message' } => record.type === 'message')
      .map((record) => ({
        id: record.id,
        role: record.role,
        content: record.content,
        createdAt: record.createdAt,
        model: record.model,
      }))

    const builtMessages = this.composer.compose(messages, {
      system: input.system,
      budget: input.budget ?? this.defaultBudget,
      includeHistory: true,
    })

    const includedMessageIds = new Set(builtMessages.messages.map((message) => message.id))
    const contextItems: ModelContextItem[] = []

    for (const record of input.records) {
      if (record.type === 'message') {
        if (includedMessageIds.has(record.id)) {
          contextItems.push({
            kind: 'message',
            message: {
              id: record.id,
              role: record.role,
              content: record.content,
              createdAt: record.createdAt,
              model: record.model,
            },
          })
        }
        continue
      }

      if (record.type === 'tool_use') {
        contextItems.push({
          kind: 'tool_use',
          id: record.id,
          tool: record.tool,
          input: record.input,
        })
        continue
      }

      if (record.type === 'tool_result') {
        contextItems.push({
          kind: 'tool_result',
          toolUseId: record.toolUseId,
          tool: record.tool,
          ok: record.ok,
          content: record.content,
        })
      }
    }

    return {
      system: builtMessages.system,
      messages: builtMessages.messages,
      contextItems,
    }
  }
}

import { randomUUID } from 'node:crypto'
import { ContextBuilder } from './contextBuilder.js'
import { ToolRunner } from './toolRunner.js'
import type { ChatMessage, ModelProvider, SessionRecord, Tool, ToolContext } from './types.js'

export interface AgentLoopOptions {
  provider: ModelProvider
  model: string
  maxTokens?: number
  tools: Tool[]
  contextBuilder: ContextBuilder
  toolRunner: ToolRunner
  toolContext: ToolContext
  system?: string
  loadRecords(): Promise<SessionRecord[]>
  appendRecord(record: SessionRecord): Promise<void>
}

export class AgentLoop {
  constructor(private readonly options: AgentLoopOptions) {}

  async run(userInput: string): Promise<string> {
    const userMessage: ChatMessage & { type: 'message' } = {
      type: 'message',
      id: randomUUID(),
      role: 'user',
      content: userInput,
      createdAt: new Date().toISOString(),
    }
    await this.options.appendRecord(userMessage)

    for (let iteration = 0; iteration < 8; iteration++) {
      const records = await this.options.loadRecords()
      const built = this.options.contextBuilder.build({
        records,
        tools: this.options.tools,
        system: this.options.system,
      })
      const response = await this.options.provider.createMessage({
        system: built.system,
        messages: built.messages,
        contextItems: built.contextItems,
        tools: this.options.tools,
        model: this.options.model,
        maxTokens: this.options.maxTokens,
      })

      const assistantMessage: ChatMessage & { type: 'message' } = {
        type: 'message',
        id: randomUUID(),
        role: 'assistant',
        content: response.content,
        createdAt: new Date().toISOString(),
        model: this.options.model,
      }
      await this.options.appendRecord(assistantMessage)

      if (response.toolCalls.length === 0) {
        return response.content
      }

      for (const toolCall of response.toolCalls) {
        await this.options.toolRunner.run(toolCall, this.options.toolContext)
      }
    }

    throw new Error('Agent loop exceeded maximum tool iterations')
  }
}

import type { ChatMessage } from '../harness/types.js'
import { ContextBudget } from './budget.js'

export interface ComposerOptions {
  system?: string
  budget: ContextBudget
  includeHistory?: boolean
}

export class PromptComposer {
  compose(
    messages: ChatMessage[],
    options: ComposerOptions,
  ): { system?: string; messages: ChatMessage[] } {
    const { system, budget, includeHistory = true } = options

    if (!includeHistory) {
      return { system, messages: [] }
    }

    const truncatedMessages = budget.truncate(messages, system)
    return { system, messages: truncatedMessages }
  }

  buildRequestMessages(
    messages: ChatMessage[],
    options: ComposerOptions,
  ): { system?: string; messages: ChatMessage[] } {
    return this.compose(messages, options)
  }
}

import type { ChatMessage } from '../harness/types.js'

export interface TokenCount {
  total: number
  messages: number[]
}

function countTokens(text: string): number {
  // Rough estimate: ~4 chars per token for English, more for CJK
  // This is a simplified approximation for the MVP
  let count = 0
  for (const char of text) {
    if (char.charCodeAt(0) > 127) {
      count += 2 // CJK characters
    } else {
      count += 0.25 // English/ASCII
    }
  }
  return Math.ceil(count)
}

export function countMessageTokens(message: ChatMessage): number {
  return countTokens(message.content)
}

export function countMessagesTokens(messages: ChatMessage[]): TokenCount {
  const counts = messages.map(countMessageTokens)
  return {
    total: counts.reduce((a, b) => a + b, 0),
    messages: counts,
  }
}

export class ContextBudget {
  private budget: number

  constructor(budget: number = 100_000) {
    this.budget = budget
  }

  getBudget(): number {
    return this.budget
  }

  setBudget(budget: number): void {
    this.budget = budget
  }

  truncate(messages: ChatMessage[], system?: string): ChatMessage[] {
    const systemTokens = system ? countTokens(system) : 0
    const availableBudget = this.budget - systemTokens - 1000 // Reserve for response

    if (availableBudget <= 0) {
      return []
    }

    const result: ChatMessage[] = []
    let used = 0

    // Add messages from oldest to newest until budget is exhausted
    for (const message of messages) {
      const tokens = countMessageTokens(message)
      if (used + tokens > availableBudget) {
        break
      }
      result.push(message)
      used += tokens
    }

    return result
  }

  estimate(messages: ChatMessage[], system?: string): { used: number; budget: number; remaining: number } {
    const used = countMessagesTokens(messages).total + (system ? countTokens(system) : 0)
    return {
      used,
      budget: this.budget,
      remaining: Math.max(0, this.budget - used),
    }
  }
}

#!/usr/bin/env node

import readline from 'node:readline'
import { ConfigService } from '../config/service.js'
import { createProvider } from '../config/providers.js'
import { SessionStore, type SessionMeta } from '../sessions/service.js'
import { getBuiltinTools } from '../tools/index.js'
import { PermissionGate } from '../harness/permissions.js'
import { ToolRunner } from '../harness/toolRunner.js'
import { ContextBuilder } from '../harness/contextBuilder.js'
import { AgentLoop } from '../harness/loop.js'
import type { SessionRecord } from '../harness/types.js'
import type { PermissionRequest } from '../harness/permissions.js'

const cwd = process.cwd()

async function main() {
  const args = process.argv.slice(2)
  const command = args[0] ?? 'help'

  switch (command) {
    case 'help':
      printHelp()
      break

    case 'new':
      await runNewSession()
      break

    case 'list':
      await listSessions()
      break

    case 'resume': {
      const sessionId = args[1]
      if (!sessionId) {
        console.error('Usage: myagent resume <session-id-or-prefix>')
        process.exit(1)
      }
      await resumeSession(sessionId)
      break
    }

    default:
      console.error(`Unknown command: ${command}`)
      console.error('Run "myagent help" for usage information')
      process.exit(1)
  }
}

function printHelp() {
  console.log(`
MyAgent CLI

Usage:
  myagent [command]

Commands:
  new             Start a new interactive session
  list            List saved sessions with usable IDs
  resume <id>     Resume a session by full ID or unambiguous prefix
  help            Show this help message

During a session:
  - type your prompt and press Enter
  - type /exit to quit
`)
}

async function runNewSession() {
  const store = new SessionStore(cwd)
  await store.init()
  const session = await store.create()
  await startInteractiveSession(session)
}

async function resumeSession(sessionId: string) {
  const store = new SessionStore(cwd)
  await store.init()
  const session = await store.resolve(sessionId)
  if (!session) {
    console.error(`Session not found or ambiguous: ${sessionId}`)
    process.exit(1)
  }
  await startInteractiveSession(session)
}

async function startInteractiveSession(session: SessionMeta) {
  const config = new ConfigService(cwd)
  await config.load()

  const modelConfig = config.getDefaultModel()
  if (!modelConfig) {
    console.error('No default model configured.')
    process.exit(1)
  }

  const provider = createProvider(modelConfig)
  if (!provider) {
    console.error(`Failed to create provider for: ${modelConfig.provider}`)
    process.exit(1)
  }

  const store = new SessionStore(cwd)
  await store.init()
  const tools = getBuiltinTools()
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  })

  const permissionGate = new PermissionGate((request) => promptPermission(rl, request))
  const toolRunner = new ToolRunner(tools, permissionGate, {
    onRecord: async (record) => {
      await store.appendRecord(session.id, record)
    },
  })

  const loop = new AgentLoop({
    provider,
    model: modelConfig.model,
    maxTokens: config.get().agent.maxTokens,
    tools,
    contextBuilder: new ContextBuilder(),
    toolRunner,
    toolContext: { cwd, sessionId: session.id, readFiles: new Set() },
    system: config.get().agent.system,
    loadRecords: async () => store.loadRecords(session.id),
    appendRecord: async (record) => store.appendRecord(session.id, record),
  })

  const records = await store.loadRecords(session.id)
  const messageCount = records.filter((record) => record.type === 'message').length
  console.log(`Session: ${session.shortId} (${session.id})`)
  console.log(`Using model: ${modelConfig.model} (${provider.name} format)`)
  if (modelConfig.baseUrl) {
    console.log(`Provider wire format: ${provider.name}`)
  }
  if (messageCount > 0) {
    console.log(`Loaded ${messageCount} previous messages.`)
  }
  console.log('Type /exit to quit.\n')

  const prompt = () => {
    rl.question('> ', async (input) => {
      const trimmed = input.trim()
      if (trimmed === '/exit' || trimmed === 'exit') {
        rl.close()
        return
      }
      if (!trimmed) {
        prompt()
        return
      }

      try {
        console.log('\nThinking...\n')
        const response = await loop.run(trimmed)
        if (response) console.log(response)
      } catch (error) {
        console.error(error instanceof Error ? error.message : String(error))
      }

      console.log()
      prompt()
    })
  }

  prompt()
}

async function promptPermission(rl: readline.Interface, request: PermissionRequest): Promise<boolean> {
  const summary = JSON.stringify(request.input)
  const answer = await askQuestion(
    rl,
    `[permission] ${request.tool.name}: ${request.reason}\ninput: ${summary}\nAllow? (y/N) `,
  )
  return /^(y|yes)$/i.test(answer.trim())
}

function askQuestion(rl: readline.Interface, question: string): Promise<string> {
  return new Promise((resolve) => {
    rl.question(question, resolve)
  })
}

async function listSessions() {
  const store = new SessionStore(cwd)
  await store.init()

  const sessions = await store.list()
  if (sessions.length === 0) {
    console.log('No sessions found.')
    return
  }

  console.log('Sessions:\n')
  for (const session of sessions) {
    const date = new Date(session.updatedAt).toLocaleString()
    const title = session.title ?? '(untitled)'
    console.log(`  ${session.shortId}  ${session.id}  ${session.messageCount} msgs  ${date}  ${title}`)
  }
}

main().catch((error) => {
  console.error('Fatal error:', error)
  process.exit(1)
})
